-- Wikidata Q-IDs for bio'd artists.
-- Generated by scripts/backfill-wikidata-ids.mjs.
-- Each Q-ID was selected by:
--   * Wikidata wbsearchentities lookup on the display name.
--   * wbgetentities verification of:
--       - instance_of includes human (Q5)
--       - occupation includes a recognized art occupation
--       - date_of_birth year is within ±5 of our row
-- Rows with no confident match are emitted as comments.

-- Alessandro Algardi (1598–1654)  →  Q336798  Italian sculptor (1598–1654)
update public.artists set wikidata_id = 'Q336798' where slug in ('alessandro-algardi');

-- Alessandro Allori (1535–1607)  →  Q333369  Italian painter (1535–1607)
update public.artists set wikidata_id = 'Q333369' where slug in ('alessandro-allori');

-- Alessandro Casolani (1552–1606)  →  Q461700  Italian painter
update public.artists set wikidata_id = 'Q461700' where slug in ('alessandro-casolani');

-- Alessandro Magnasco (1667–1749)  →  Q516941  Italian painter (1667-1749)
update public.artists set wikidata_id = 'Q516941' where slug in ('alessandro-magnasco');

-- Alessandro Tiarini (1577–1668)  →  Q2248508  Italian painter (1577-1668)
update public.artists set wikidata_id = 'Q2248508' where slug in ('alessandro-tiarini');

-- Cosmè Tura (Cosimo di Domenico di Bonaventura) (1433–1495)  →  Q7129  Italian painter (1430-1495)
update public.artists set wikidata_id = 'Q7129' where slug in ('cosm-tura-cosimo-di-domenico-di-bonaventura');

-- Francesco Salviati (Francesco de' Rossi) (1510–1563)  →  Q704594  Italian painter (1510–1563)
update public.artists set wikidata_id = 'Q704594' where slug in ('francesco-salviati-francesco-de-rossi');

