-- Manual overrides:
--   * Segna di Buonaventura — Q-ID from rejection log (DB birth year
--     1298 vs Wikidata's c.1280 is too wide for the script's tolerance).
--   * The three "Master of X Psalter" entries are anonymous workshops
--     and have no individual Wikidata person Q. They are pointed at the
--     respective manuscript entities — the manuscript is the canonical
--     Wikidata reference for the unnamed master in each case.
-- ─────────────────────────────────────────────────────────────────────

-- Segna di Buonaventura — Sienese painter and Duccio pupil, c.1280–1331.
update public.artists set wikidata_id = 'Q929809' where slug = 'segna-di-buonaventura';

